module unsigned_min(
  input [31:0] a, b, c, d,
  output reg [31:0] min
);
  wire [31:0] _tap_a = a & {32{1'b1}};


  always @(*) begin
    if(a < b && a < c && a < d)
      min = a;
    else if(b < c && b < d)
      min = b;
    else if(c < d)
      min = c;
    else
      min = d;
  end

endmodule
